const raw = $input.first().json.output || "";
const data = $("Extrair Dados SSL").first().json;
const fence = String.fromCharCode(96).repeat(3);
let html = String(raw);
html = html.split(fence + "html").join("");
html = html.split(fence + "HTML").join("");
html = html.split(fence).join("");
html = html.trim();
const grade = (data && data.grade) ? data.grade : "Indisponível";
const host = (data && data.host) ? data.host : "domínio";
const subject = "Diagnóstico de Segurança - " + host + " (Nota " + grade + ")";
return [{ json: { emailHtml: html, subject: subject, host: host, grade: grade } }];

const data = $("Consultar Status").first().json;
const host = ($("Normalizar Entrada").first().json.domain) || "domínio";
